#include<bits/stdc++.h>
using namespace std;

const int N = 500 + 5;
const int M = 500 + 5;

int n, m, s, x;

int dis[N], a[N], ans = 2e9;
bool vis[N];

struct Edge
{
    int v, w, c;
};
vector<Edge> e[N];


int SPFA(int minc)
{
    queue<int> q;
    memset(dis, 0x3f, sizeof dis);
    dis[s] = 0, vis[s] = 1;
    q.push(s);
    while(!q.empty())
    {
        int u = q.front();
        q.pop();
        vis[u] = 0;
        for(auto [v, w, c] : e[u])
        {
        	if(c < minc) continue;
            if(dis[v] > dis[u] + w)
            {
                dis[v] = dis[u] + w;
                if(!vis[v]) q.push(v), vis[v] = 1;
            }
        }
    }
    return dis[n] + x / minc;
}

int main()
{
    cin.tie(0) -> sync_with_stdio(0);
    s = 1;
    cin >> n >> m >> x;
    for(int i = 1; i <= m; i++)
    {
        int u, v, w, c;
        cin >> u >> v >> w >> c;
        e[u].push_back({v, w, c});
        e[v].push_back({u, w, c});
        a[i] = c;
    }
    for(int i = 1; i <= m; i++)
	    ans = min(ans, SPFA(a[i]));
	cout << ans;
    return 0;
}
